import{_ as r,a as e,b as a,c as o,d as i}from"./chunks/fig9.Oq9aRFns.js";import{_ as n,c as l,o as s,ae as g}from"./chunks/framework.Bzon8x8e.js";const b=JSON.parse('{"title":"Глубокое трансферное обучение (SDTL) для оценки состояния здоровья (SOH) литий-ионных аккумуляторов в кросс-сценарных приложениях","description":"","frontmatter":{},"headers":[],"relativePath":"ru/index.md","filePath":"ru/index.md"}'),h={name:"ru/index.md"};function d(p,t,c,u,m,f){return s(),l("div",null,[...t[0]||(t[0]=[g('<h1 id="глубокое-трансферное-обучение-sdtl-для-оценки-состояния-здоровья-soh-литии-ионных-аккумуляторов-в-кросс-сценарных-приложениях" tabindex="-1">Глубокое трансферное обучение (SDTL) для оценки состояния здоровья (SOH) литий-ионных аккумуляторов в кросс-сценарных приложениях <a class="header-anchor" href="#глубокое-трансферное-обучение-sdtl-для-оценки-состояния-здоровья-soh-литии-ионных-аккумуляторов-в-кросс-сценарных-приложениях" aria-label="Permalink to &quot;Глубокое трансферное обучение (SDTL) для оценки состояния здоровья (SOH) литий-ионных аккумуляторов в кросс-сценарных приложениях&quot;">​</a></h1><h2 id="i-введение" tabindex="-1">I. Введение <a class="header-anchor" href="#i-введение" aria-label="Permalink to &quot;I. Введение&quot;">​</a></h2><p>С взрывным ростом электромобилей и систем накопления энергии точная оценка <strong>состояния здоровья (State of Health, SOH)</strong> литий-ионных батарей имеет решающее значение для обеспечения безопасности системы и продления срока службы батареи.</p><p>Однако в практических приложениях мы сталкиваемся с двумя основными проблемами:</p><ul><li><strong>Сложная и переменная среда</strong>: Различные материалы катодов (такие как NCM, NCA), резкие колебания температуры окружающей среды и разнообразные протоколы зарядки-разрядки.</li><li><strong>Отдельные хранилища данных и нехватка образцов</strong>: Новые батареи имеют исключительно ограниченные данные в начальный период эксплуатации, в то время как традиционные модели глубокого обучения часто требуют огромных объемов помеченных данных для достижения хорошей способности обобщения.</li></ul><p>Для решения этих проблем статья, опубликованная в престижном журнале <em>Journal of Power Sources</em> под названием <em><strong>Deep transfer learning enabled online state-of-health estimation of lithium-ion batteries under small samples across different cathode materials</strong></em>, представляет новейшие результаты исследований: метод <strong>глубокого трансферного обучения (SDTL)</strong> на основе <strong>механизма самовнимания</strong>.</p><h2 id="ii-архитектура-sdtl" tabindex="-1">II. Архитектура SDTL <a class="header-anchor" href="#ii-архитектура-sdtl" aria-label="Permalink to &quot;II. Архитектура SDTL&quot;">​</a></h2><p>В исследовании предложена эффективная система SDTL с тремя основными компонентами: <strong>извлечение признаков</strong>, <strong>предварительное обучение</strong> и <strong>тонкая настройка</strong>:</p><p align="center"><img src="'+r+'" style="width:100%;margin:0 auto;display:block;"></p><p align="center" style="color:grey;">Архитектура системы глубокого трансферного обучения (SDTL) на основе механизма самовнимания</p><h3 id="_1-извлечение-многоисточниковых-индикаторов-здоровья-hi" tabindex="-1">1. Извлечение многоисточниковых индикаторов здоровья (HI) <a class="header-anchor" href="#_1-извлечение-многоисточниковых-индикаторов-здоровья-hi" aria-label="Permalink to &quot;1. Извлечение многоисточниковых индикаторов здоровья (HI)&quot;">​</a></h3><p>Исследователи извлекли <strong>18 индикаторов здоровья</strong> из напряжения/тока заряда, напряжения/тока разряда и кривых дополнительной емкости (IC). Используя <strong>коэффициент корреляции Пирсона (PCC)</strong> для фильтрации признаков, высоко коррелирующих с SOH (таких как HI3, HI5, HI11 и т. д.), они обеспечили физическую интерпретируемость и способность представления входных данных.</p><p align="center"><img src="'+e+'" style="width:100%;margin:0 auto;display:block;"></p><p align="center" style="color:grey;">Анализ коэффициента корреляции Пирсона (PCC) между извлеченными индикаторами здоровья (HI) и SOH</p><h3 id="_2-механизм-самовнимания-self-attention" tabindex="-1">2. Механизм самовнимания (Self-Attention) <a class="header-anchor" href="#_2-механизм-самовнимания-self-attention" aria-label="Permalink to &quot;2. Механизм самовнимания (Self-Attention)&quot;">​</a></h3><p>В отличие от традиционных RNN или LSTM, SDTL использует <strong>многоголовый механизм самовнимания</strong>. Он захватывает глобальные зависимости в разных позициях временного ряда и автоматически присваивает веса наиболее критичным характеристикам деградации, обеспечивая более точное выявление закономерностей деградации батареи в различных условиях эксплуатации.</p><p align="center"><img src="'+a+'" style="width:100%;margin:0 auto;display:block;"></p><p align="center" style="color:grey;">Диаграмма архитектуры многоголового модуля самовнимания</p><h3 id="_3-глубокое-трансферное-обучение" tabindex="-1">3. Глубокое трансферное обучение <a class="header-anchor" href="#_3-глубокое-трансферное-обучение" aria-label="Permalink to &quot;3. Глубокое трансферное обучение&quot;">​</a></h3><ul><li><strong>Предварительное обучение (Offline)</strong>: Использование больших объемов исторических данных батареги (исходный домен) для предварительного обучения, позволяя модели изучать общие закономерности деградации батареи.</li><li><strong>Тонкая настройка (Online)</strong>: Для новых задач с батареями (целевой домен) требуются только данные первых 10% ранних циклов для завершения онлайн-адаптации. Путем замораживания слоев извлечения признаков нижнего уровня и обновления только параметров выходного слоя достигается быстрая и экономичная кросс-сценарная передача.</li></ul><h2 id="iii-экспериментальная-валидация" tabindex="-1">III. Экспериментальная валидация <a class="header-anchor" href="#iii-экспериментальная-валидация" aria-label="Permalink to &quot;III. Экспериментальная валидация&quot;">​</a></h2><p>Для проверки способности обобщения SDTL исследователи провели чрезвычайно строгие экспериментальные тесты:</p><p align="center"><img src="'+o+'" style="width:100%;margin:0 auto;display:block;"></p><p align="center" style="color:grey;">Результаты оценки SOH модели SDTL на экспериментальных данных батареи</p><ul><li><strong>Полное охватывание наборов данных</strong>: Включает самостоятельно построенные наборы данных NCM батарей (коэффициенты 1C/2C) и публично доступные наборы данных NCA батарей NASA (охватывающие температуру окружающей среды 24°C и 4°C).</li><li><strong>Результаты производительности</strong>: Экспериментальные результаты показывают, что даже в сложных условиях, таких как низкая температура (4°C) и высокие скорости разряда, SDTL демонстрирует исключительно высокую точность оценки и устойчивость.</li><li><strong>Сравнительные преимущества</strong>: По сравнению с основными алгоритмами глубокого обучения и другими методами трансферного обучения, SDTL показывает явные преимущества в сценариях с небольшим количеством образцов, устраняя высокую стоимость обучения моделей с нуля.</li></ul><p align="center"><img src="'+i+'" style="width:100%;margin:0 auto;display:block;"></p><p align="center" style="color:grey;">Сравнение производительности прогнозирования между SDTL и основными моделями (CNN-LSTM, GRU, ResNet)</p><h2 id="iv-заключение" tabindex="-1">IV. Заключение <a class="header-anchor" href="#iv-заключение" aria-label="Permalink to &quot;IV. Заключение&quot;">​</a></h2><p>Вклады статьи в основном отражаются в:</p><ul><li><strong>Эффективность</strong>: Быстрая онлайн-адаптация может быть достигнута всего с 10% данных.</li><li><strong>Широкая применимость</strong>: Может работать с различными материалами катодов (NCM vs NCA) и колебаниями температуры окружающей среды.</li><li><strong>Инженерная ценность</strong>: Предоставляет практическое, легковесное и высокоточное решение для онлайн-оценки SOH для BMS (систем управления батареями).</li></ul><hr><h2 id="справочная-информация" tabindex="-1">Справочная информация <a class="header-anchor" href="#справочная-информация" aria-label="Permalink to &quot;Справочная информация&quot;">​</a></h2><ul><li><strong>Название</strong>: Deep transfer learning enabled online state-of-health estimation of lithium-ion batteries under small samples across different cathode materials, ambient temperature and charge-discharge protocols</li><li><strong>Журнал</strong>: Journal of Power Sources (2025)</li><li><strong>DOI</strong>: 10.1016/j.jpowsour.2025.237503</li><li><strong>Ссылка</strong>: <a href="https://doi.org/10.1016/j.jpowsour.2025.237503" target="_blank" rel="noreferrer">https://doi.org/10.1016/j.jpowsour.2025.237503</a></li></ul>',33)])])}const I=n(h,[["render",d]]);export{b as __pageData,I as default};
